'use client';

import {
  Collapsible,
  CollapsibleContent,
  CollapsibleTrigger,
} from '@/components/ui/collapsible';
import {cn} from '@/lib/utils';

// ---------------------------------------------------------------------------
// Types
// ---------------------------------------------------------------------------

type AgentPendingItemProps = React.ComponentProps<'div'> & {
  /** Short description of what needs human input. */
  label: string;
  /** Optional context and action buttons revealed when expanded. */
  children?: React.ReactNode;
};

// ---------------------------------------------------------------------------
// Component
// ---------------------------------------------------------------------------

/**
 * An expandable row for agent actions that need human input.
 * Collapsed state is a single 36px row with a warning dot prefix.
 * Expanded state reveals the children slot (Radix Collapsible unmounts when closed).
 *
 * @see §11 Agent Patterns — Pending item in the Trident Visual Language spec
 *
 * @wcag 4.1.2 — CollapsibleTrigger carries aria-expanded automatically
 */
function AgentPendingItem({
  label,
  children,
  className,
  ...props
}: AgentPendingItemProps) {
  return (
    <Collapsible asChild>
      <div
        data-slot="pending-item"
        className={cn('flex flex-col', className)}
        {...props}
      >
        <CollapsibleTrigger className="flex h-9 items-center gap-2 text-left text-sm font-[520] text-foreground focus-visible:ring-2 focus-visible:ring-ring focus-visible:outline-none">
          <span
            aria-hidden="true"
            className="size-2 shrink-0 rounded-full bg-warning"
          />
          <span className="min-w-0 truncate">{label}</span>
        </CollapsibleTrigger>

        {children && (
          <CollapsibleContent>
            <div
              data-slot="pending-item-body"
              className="pt-1 pb-3 text-sm text-foreground"
            >
              {children}
            </div>
          </CollapsibleContent>
        )}
      </div>
    </Collapsible>
  );
}

// ---------------------------------------------------------------------------
// Exports
// ---------------------------------------------------------------------------

export {AgentPendingItem};
export type {AgentPendingItemProps};
